import{_ as e,o as r,c as a,ag as s,ah as o}from"./chunks/framework.D9bIGSBm.js";const u=JSON.parse('{"title":"任务与工作区","description":"","frontmatter":{},"headers":[],"relativePath":"features/tasks-and-workspaces.md","filePath":"features/tasks-and-workspaces.md"}'),d={name:"features/tasks-and-workspaces.md"};function l(n,t,i,h,c,g){return r(),a("div",null,[...t[0]||(t[0]=[s('<h1 id="任务与工作区" tabindex="-1">任务与工作区 <a class="header-anchor" href="#任务与工作区" aria-label="Permalink to &quot;任务与工作区&quot;">​</a></h1><p>LoongCode 用<strong>工作区</strong>（Workspace，对应你磁盘上的项目目录）和<strong>任务</strong>（Task，对应一次 AI 对话会话）两级结构来组织你的工作。本页介绍如何添加工作区、管理任务生命周期，以及置顶、搜索、归档等高效操作。</p><blockquote><p>如果你还没开始第一个任务，建议先看<a href="/docs/guide/quick-start.html">快速上手</a>了解基础操作流程。</p></blockquote><p><img src="'+o+'" alt="截图：左侧任务栏展开状态，显示搜索框、＋ 打开工作区、＋ 新建任务、置顶组、任务列表各区域"></p><hr><h2 id="左侧任务栏布局" tabindex="-1">左侧任务栏布局 <a class="header-anchor" href="#左侧任务栏布局" aria-label="Permalink to &quot;左侧任务栏布局&quot;">​</a></h2><p>左侧任务栏从上到下的真实元素顺序为：</p><table tabindex="0"><thead><tr><th>区域</th><th>说明</th></tr></thead><tbody><tr><td><strong>Logo / 折叠按钮</strong></td><td>悬浮后可折叠侧栏（v0.7.0 起）</td></tr><tr><td><strong>搜索框</strong></td><td>按关键词实时筛选任务</td></tr><tr><td><strong>＋ 打开工作区</strong></td><td>添加项目文件夹为工作区</td></tr><tr><td><strong>＋ 新建任务</strong></td><td>快速新建一个任务草稿</td></tr><tr><td><strong>已置顶</strong></td><td>已置顶任务集合，独立于分组折叠</td></tr><tr><td><strong>任务大组头</strong></td><td>含「任务 / 归档」标签与视图切换（分组列表 / 时间线）</td></tr><tr><td><strong>工作区树 + 任务列表</strong></td><td>按工作区分组，展示各任务</td></tr><tr><td><strong>底部栏</strong></td><td>新手引导、移动端支持、打开设置</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">快捷键</p><ul><li><code>Ctrl+N</code>：新建任务草稿（任意界面可用）</li><li>悬浮 Logo 点击：折叠 / 展开左侧任务栏（v0.7.0）</li></ul></div><hr><h2 id="添加与管理工作区" tabindex="-1">添加与管理工作区 <a class="header-anchor" href="#添加与管理工作区" aria-label="Permalink to &quot;添加与管理工作区&quot;">​</a></h2><h3 id="添加工作区" tabindex="-1">添加工作区 <a class="header-anchor" href="#添加工作区" aria-label="Permalink to &quot;添加工作区&quot;">​</a></h3><ol><li>点击搜索框下方的**＋ 打开工作区**按钮。</li><li>在弹出的文件夹选取对话框中选择本地项目目录，点击<strong>确认</strong>。</li><li>如果该目录下有 Claude Code 历史会话，会弹出询问「<strong>同步会话</strong>」——点<strong>导入</strong>可将历史记录导入为任务；点<strong>跳过</strong>则跳过。</li></ol><p>工作区添加成功后会出现在任务列表树中。</p><h3 id="工作区操作" tabindex="-1">工作区操作 <a class="header-anchor" href="#工作区操作" aria-label="Permalink to &quot;工作区操作&quot;">​</a></h3><p>鼠标悬浮到工作区名称行，右侧出现三个快捷图标：</p><ul><li><strong>新建任务</strong>（<code>shell.newTaskForWs</code>）：在该工作区下新建任务</li><li><strong>查看文件</strong>：跳转到右侧面板的文件树视图</li><li><strong>移除工作区</strong>：从 LoongCode 中移除该工作区条目（<strong>不影响磁盘上的实际文件</strong>）</li></ul><div class="warning custom-block"><p class="custom-block-title">移除工作区</p><p>移除工作区会删除该工作区下的所有任务记录（<code>shell.removeWorkspaceDesc</code>：界面原文如此），但磁盘上的代码与历史文件不受影响。</p></div><hr><h2 id="新建任务" tabindex="-1">新建任务 <a class="header-anchor" href="#新建任务" aria-label="Permalink to &quot;新建任务&quot;">​</a></h2><h3 id="草稿态机制" tabindex="-1">草稿态机制 <a class="header-anchor" href="#草稿态机制" aria-label="Permalink to &quot;草稿态机制&quot;">​</a></h3><p>点击**＋ 新建任务**（或按 <code>Ctrl+N</code>）后，任务进入<strong>草稿态</strong>——此时尚未写入数据库，主区域内联显示配置选择器供你挑选工作区、模型、Git 分支或 worktree（Git worktree 是 Git 的独立检出目录，允许同时在多个分支上工作）。</p><p><strong>发送第一条消息后，任务才正式创建</strong>，这样可以避免空任务堆积。</p><p>草稿会默认选中上次用过的工作区，少点一步。草稿选中的工作区被外部删除时，发送按钮会被禁用并给出提示。</p><h3 id="草稿态下可用功能" tabindex="-1">草稿态下可用功能 <a class="header-anchor" href="#草稿态下可用功能" aria-label="Permalink to &quot;草稿态下可用功能&quot;">​</a></h3><p>即使任务还在草稿态，右侧面板的文件树、编辑器、审查、浏览器、终端均可正常使用，它们按工作区工作，不依赖任务是否已落盘。</p><hr><h2 id="任务状态" tabindex="-1">任务状态 <a class="header-anchor" href="#任务状态" aria-label="Permalink to &quot;任务状态&quot;">​</a></h2><p>每个任务行左侧的彩色圆点表示当前状态，共五种：</p><table tabindex="0"><thead><tr><th>状态</th><th>含义</th></tr></thead><tbody><tr><td><strong>空闲</strong></td><td>无正在运行的回合</td></tr><tr><td><strong>运行中</strong></td><td>AI 正在生成回复或执行工具</td></tr><tr><td><strong>成功</strong></td><td>最近一轮回合正常结束</td></tr><tr><td><strong>出错</strong></td><td>最近一轮回合以错误结束</td></tr><tr><td><strong>提问中</strong></td><td>AI 正在等你回答一个问题，任务行蓝色高亮</td></tr></tbody></table><hr><h2 id="任务排序与置顶" tabindex="-1">任务排序与置顶 <a class="header-anchor" href="#任务排序与置顶" aria-label="Permalink to &quot;任务排序与置顶&quot;">​</a></h2><h3 id="按最近活动排序" tabindex="-1">按最近活动排序 <a class="header-anchor" href="#按最近活动排序" aria-label="Permalink to &quot;按最近活动排序&quot;">​</a></h3><p>任务列表与时间线分桶按<strong>最近活动时间</strong>排序——刚发过消息或刚结束一轮对话的任务会自动浮到前面（v0.4.2 起）。</p><h3 id="置顶任务" tabindex="-1">置顶任务 <a class="header-anchor" href="#置顶任务" aria-label="Permalink to &quot;置顶任务&quot;">​</a></h3><p>对于常用任务，可以将其置顶：</p><ol><li>右键点击任务行（或点击行尾的操作菜单）。</li><li>选择<strong>置顶任务</strong>（界面文案：<code>shell.pinTask</code>）。</li></ol><p>置顶后任务出现在<strong>已置顶</strong>分组，跨视图、不受「折叠全部」影响。取消置顶选<strong>取消置顶</strong>（<code>shell.unpinTask</code>）即可。</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>置顶任务受自动归档保护，不会被自动归档。</p></div><hr><h2 id="搜索任务" tabindex="-1">搜索任务 <a class="header-anchor" href="#搜索任务" aria-label="Permalink to &quot;搜索任务&quot;">​</a></h2><p>搜索框（输入框占位符文案：<code>composer.searchTaskPlaceholder</code> 「搜索任务…」）位于侧栏顶部 Logo 区域下方，输入关键词后任务列表实时筛选。</p><ul><li>无匹配时显示：「未找到匹配任务」（<code>shell.noMatchedTasks</code>）</li><li>点击搜索框右侧的「清除搜索」按钮（<code>composer.searchClear</code>）可清空关键词</li></ul><hr><h2 id="归档任务" tabindex="-1">归档任务 <a class="header-anchor" href="#归档任务" aria-label="Permalink to &quot;归档任务&quot;">​</a></h2><h3 id="手动归档" tabindex="-1">手动归档 <a class="header-anchor" href="#手动归档" aria-label="Permalink to &quot;手动归档&quot;">​</a></h3><p>右键点击任务行，选择<strong>归档</strong>（<code>shell.archiveTask</code>）；也可以在右键菜单中点<strong>归档</strong>（<code>menu.archive</code>）。</p><p>归档后任务从主列表移出，进入归档视图，主列表更加清爽。</p><p>取消归档：进入归档视图后，右键任务选<strong>取消归档</strong>（<code>shell.unarchiveTask</code> / <code>menu.unarchive</code>），任务的活动时间会被重置，回到主列表最上方，方便立即继续。</p><h3 id="自动归档" tabindex="-1">自动归档 <a class="header-anchor" href="#自动归档" aria-label="Permalink to &quot;自动归档&quot;">​</a></h3><p>应用<strong>启动时</strong>与<strong>每小时</strong>各跑一次自动归档，按「最近活动时间」超过阈值自动将久未触碰的任务归档（v0.4.3 起）。</p><p><strong>保护规则</strong>：运行中任务和已置顶任务不会被自动归档。</p><p><strong>调整阈值</strong>：在<strong>设置 → 常规</strong>中可开关自动归档，并设置阈值数值与单位（小时 / 天 / 月），默认开启、7 天。</p><h3 id="查看归档视图" tabindex="-1">查看归档视图 <a class="header-anchor" href="#查看归档视图" aria-label="Permalink to &quot;查看归档视图&quot;">​</a></h3><ol><li>在任务大组头右侧点击<strong>查看归档</strong>（<code>shell.viewArchive</code>）。</li><li>进入归档视图后，任务按归档时间降序排列。</li><li>归档视图下自动隐藏置顶区和新建入口，空态有友好提示：「暂无归档任务」（<code>shell.noArchivedTasks</code>）。</li><li>点击<strong>退出归档</strong>（<code>shell.exitArchive</code>）返回主任务列表。</li></ol><p><img src="'+o+'" alt="截图：归档视图已打开，任务按归档时间降序排列，右上角有「退出归档」按钮"></p><hr><h2 id="任务右键菜单" tabindex="-1">任务右键菜单 <a class="header-anchor" href="#任务右键菜单" aria-label="Permalink to &quot;任务右键菜单&quot;">​</a></h2><p>右键任务行可弹出包含以下操作的菜单（文案来自 shell.ts / contextMenu.ts）：</p><table tabindex="0"><thead><tr><th>操作</th><th>界面文案</th></tr></thead><tbody><tr><td>重命名</td><td><strong>重命名</strong>（<code>shell.renameTask</code>）</td></tr><tr><td>置顶 / 取消置顶</td><td><strong>置顶任务</strong> / <strong>取消置顶</strong>（<code>shell.pinTask</code> / <code>shell.unpinTask</code>）</td></tr><tr><td>归档 / 取消归档</td><td><strong>归档</strong> / <strong>取消归档</strong>（<code>shell.archiveTask</code> / <code>shell.unarchiveTask</code>）</td></tr><tr><td>删除</td><td><strong>删除</strong>（<code>shell.deleteTask</code>）</td></tr></tbody></table><div class="danger custom-block"><p class="custom-block-title">删除任务</p><p>删除操作不可恢复（界面确认弹窗文案：<code>shell.deleteTaskDesc</code>）。删除任务仅删除 LoongCode 内的任务记录，<strong>不影响磁盘上的历史 <code>.jsonl</code> 文件</strong>。</p></div><hr><h2 id="视图模式" tabindex="-1">视图模式 <a class="header-anchor" href="#视图模式" aria-label="Permalink to &quot;视图模式&quot;">​</a></h2><p>任务大组头提供两种视图切换（<code>shell.filterView</code>）：</p><ul><li><strong>分组列表</strong>（<code>shell.viewGrouped</code>）：按工作区分组展示，可展开 / 折叠各工作区</li><li><strong>时间线</strong>（<code>shell.viewTimeline</code>）：按时间桶（今天、昨天、本周……）排列，跨工作区浏览</li></ul><hr><h2 id="未读提示" tabindex="-1">未读提示 <a class="header-anchor" href="#未读提示" aria-label="Permalink to &quot;未读提示&quot;">​</a></h2><p>任务行右侧显示角标，表示该任务有未读的新消息（例如 AI 在后台完成了回复，而你正在查看其他任务）。切换到该任务查看消息后，角标自动消除。</p><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>了解任务管理之后，你可以进一步探索如何将多个任务并排显示，前往<a href="/docs/features/multi-pane.html">多任务分屏</a>了解分屏功能。</p>',71)])])}const b=e(d,[["render",l]]);export{u as __pageData,b as default};
